namespace BgControls.Windows.Input.Touch;/// <summary>/// 手势辅助类，负责管理 UI 元素的手势识别器集合、事件订阅以及冲突解析./// </summary>internal class GestureHelper{    private UIElement element;    private TouchHelper touchHelper;    private List<GestureRecognizerBase> recognizers;    private bool isGestureSubscriptionEstablished;    private WeakEventListener<GestureHelper, object, CeaseGesturesRequestedEventArgs>? ceaseGesturesRequestedListener;    private GestureRecognizerBase? leavingRecognizer;    private bool leavingRecognizerCapturedTouch;    /// <summary>    /// Initializes a new instance of the <see cref="GestureHelper"/> class.    /// </summary>    /// <param name="element">关联的 UI 元素.</param>    /// <param name="touchHelper">触控辅助对象.</param>    internal GestureHelper(UIElement element, TouchHelper touchHelper)    {        // 验证参数非空.        ArgumentNullException.ThrowIfNull(element, nameof(element));        ArgumentNullException.ThrowIfNull(touchHelper, nameof(touchHelper));        this.element = element;        this.touchHelper = touchHelper;        this.recognizers = new List<GestureRecognizerBase>();        // 从工厂创建所有已注册的手势识别器.        foreach (IGestureRecognizerFactory factory in GestureManager.GetRegisteredGestureRecognizerFactories())        {            GestureRecognizerBase recognizerInstance = factory.CreateGestureRecognizer(this.element);            recognizerInstance.TouchHelper = this.touchHelper;            this.recognizers.Add(recognizerInstance);        }        // 建立初始的触控订阅.        this.EstablishTouchSubscription();        // 使用弱监听器订阅全局停止手势请求事件，防止内存泄漏.        this.ceaseGesturesRequestedListener = new WeakEventListener<GestureHelper, object, CeaseGesturesRequestedEventArgs>(this);        this.ceaseGesturesRequestedListener.OnEventAction = (helper, source, eventArgs) =>        {            helper.TouchManager_CeaseGesturesRequested(source, eventArgs);        };        this.ceaseGesturesRequestedListener.OnDetachAction = weakEventListener =>        {            TouchManager.CeaseGesturesRequested -= weakEventListener.OnEvent;        };        TouchManager.CeaseGesturesRequested += this.ceaseGesturesRequestedListener.OnEvent;    }    /// <summary>    /// Finalizes an instance of the <see cref="GestureHelper"/> class.    /// </summary>    ~GestureHelper()    {        // 析构时卸载弱监听器.        if (this.ceaseGesturesRequestedListener != null)        {            this.ceaseGesturesRequestedListener.Detach();            this.ceaseGesturesRequestedListener = null;        }    }    /// <summary>    /// Gets or sets 手势冲突解析器.    /// </summary>    internal GestureConflictManager? GestureConflictResolver { get; set; }    /// <summary>    /// 根据当前识别器中是否有处理程序注册，动态建立或解除与 TouchManager 的事件订阅.    /// </summary>    internal void EstablishTouchSubscription()    {        // 检查是否有任何识别器拥有活跃的处理程序.        bool anyHandlersRegistered = this.recognizers.Any((GestureRecognizerBase r) => r.HasGestureHandlers);        if (!this.isGestureSubscriptionEstablished && anyHandlersRegistered)        {            // 开启订阅.            this.isGestureSubscriptionEstablished = true;            TouchManager.AddTouchEnterEventHandler(this.element, this.OnTouchEnter);            TouchManager.AddTouchDownEventHandler(this.element, this.OnTouchDown);            TouchManager.AddTouchMoveEventHandler(this.element, this.OnTouchMove);            TouchManager.AddTouchUpEventHandler(this.element, this.OnTouchUp);            TouchManager.AddTouchLeaveEventHandler(this.element, this.OnTouchLeave);        }        else if (this.isGestureSubscriptionEstablished && !anyHandlersRegistered)        {            // 关闭订阅.            this.isGestureSubscriptionEstablished = false;            TouchManager.RemoveTouchEnterEventHandler(this.element, this.OnTouchEnter);            TouchManager.RemoveTouchDownEventHandler(this.element, this.OnTouchDown);            TouchManager.RemoveTouchMoveEventHandler(this.element, this.OnTouchMove);            TouchManager.RemoveTouchUpEventHandler(this.element, this.OnTouchUp);            TouchManager.RemoveTouchLeaveEventHandler(this.element, this.OnTouchLeave);        }    }    /// <summary>    /// 获取指定类型的识别器实例.    /// </summary>    /// <typeparam name="T">识别器类型.</typeparam>    /// <returns>识别器实例.</returns>    internal T GetRecognizer<T>()        where T : GestureRecognizerBase    {        // 返回匹配类型的第一个识别器.        return (T)this.recognizers.First((GestureRecognizerBase r) => r.GetType() == typeof(T));    }    /// <summary>    /// 尝试获取指定类型的识别器实例.    /// </summary>    /// <typeparam name="T">识别器类型.</typeparam>    /// <returns>识别器实例，若未找到则返回 null.</returns>    internal T? TryGetRecognizer<T>()        where T : GestureRecognizerBase    {        // 返回匹配类型的第一个识别器，若无则返回默认值.        return (T?)this.recognizers.FirstOrDefault((GestureRecognizerBase r) => r.GetType() == typeof(T));    }    /// <summary>    /// 触控进入元素时的处理逻辑.    /// </summary>    private void OnTouchEnter(object sender, TouchEventArgs args)    {        GestureRecognizerEventArgs gestureArgs = new GestureRecognizerEventArgs((UIElement)sender, args);        foreach (GestureRecognizerBase recognizer in this.recognizers)        {            if (recognizer.HasGestureHandlers)            {                recognizer.OnTouchEnter(gestureArgs);                // 如果事件已被某个识别器处理，停止后续分发.                if (gestureArgs.Handled)                {                    break;                }                // 检查是否为当前正在离开的识别器重新获得了触控.                if (this.leavingRecognizer == recognizer)                {                    this.leavingRecognizerCapturedTouch = true;                    break;                }            }        }    }    /// <summary>    /// 触控按下时的处理逻辑.    /// </summary>    private void OnTouchDown(object sender, TouchEventArgs args)    {        GestureRecognizerEventArgs gestureArgs = new GestureRecognizerEventArgs((UIElement)sender, args);        foreach (GestureRecognizerBase recognizer in this.recognizers)        {            if (recognizer.HasGestureHandlers)            {                recognizer.OnTouchDown(gestureArgs);                if (gestureArgs.Handled)                {                    break;                }            }        }    }    /// <summary>    /// 触控移动时的处理逻辑.    /// </summary>    private void OnTouchMove(object sender, TouchEventArgs args)    {        GestureRecognizerEventArgs gestureArgs = new GestureRecognizerEventArgs((UIElement)sender, args);        foreach (GestureRecognizerBase recognizer in this.recognizers)        {            if (recognizer.HasGestureHandlers)            {                recognizer.OnTouchMove(gestureArgs);                if (gestureArgs.Handled)                {                    break;                }            }        }    }    /// <summary>    /// 触控抬起时的处理逻辑.    /// </summary>    private void OnTouchUp(object sender, TouchEventArgs args)    {        GestureRecognizerEventArgs gestureArgs = new GestureRecognizerEventArgs((UIElement)sender, args);        foreach (GestureRecognizerBase recognizer in this.recognizers)        {            if (recognizer.HasGestureHandlers)            {                recognizer.OnTouchUp(gestureArgs);                if (gestureArgs.Handled)                {                    break;                }            }        }    }    /// <summary>    /// 触控离开元素时的处理逻辑.    /// </summary>    private void OnTouchLeave(object sender, TouchEventArgs args)    {        GestureRecognizerEventArgs gestureArgs = new GestureRecognizerEventArgs((UIElement)sender, args);        this.leavingRecognizerCapturedTouch = false;        foreach (GestureRecognizerBase recognizer in this.recognizers)        {            GestureRecognizerBase currentRecognizer = recognizer;            this.leavingRecognizer = currentRecognizer;            if (currentRecognizer.HasGestureHandlers)            {                currentRecognizer.OnTouchLeave(gestureArgs);                // 如果事件已处理或识别器在此过程中捕获了触控，则中断.                if (gestureArgs.Handled || this.leavingRecognizerCapturedTouch)                {                    break;                }            }        }        // 清理离开状态标识.        this.leavingRecognizer = null;        this.leavingRecognizerCapturedTouch = false;    }    /// <summary>    /// 响应全局停止手势请求的处理逻辑.    /// </summary>    private void TouchManager_CeaseGesturesRequested(object? sender, CeaseGesturesRequestedEventArgs e)    {        // 如果指定了根元素且当前元素不在其范围内，则跳过.        if (e.Root != null && !e.Root.IsAncestorOf(this.element))        {            return;        }        // 通告所有识别器停止手势操作.        foreach (GestureRecognizerBase recognizer in this.recognizers)        {            recognizer.OnCeaseGesturesRequested();        }    }}